-- Buffalo Dogs - BOG - Brotherhood of Growth
-- Supabase schema, enums, tables, indexes, helper functions, and RLS policies
-- Intended for a Next.js + Supabase deployment
create extension if not exists pgcrypto;
create type public.app_role as enum ('member', 'leader', 'admin');
create type public.pack_rank as enum ('lone_wolf', 'omega', 'beta', 'delta', 'alpha', 'council');
create type public.meeting_status as enum ('draft', 'published', 'archived');
create type public.document_category as enum ('brochure','checklist','agenda_template','scholarship','meeting_notes','community_project','other');
create type public.scholarship_status as enum ('submitted', 'under_review', 'finalist', 'awarded', 'rejected');
create type public.merch_order_status as enum ('new', 'contacted', 'paid', 'fulfilled', 'cancelled');
create type public.thread_category as enum ('leadership', 'accountability', 'scholarship', 'merch', 'meetings', 'support', 'open');
create type public.join_request_status as enum ('submitted', 'reviewing', 'approved', 'declined');
create or replace function public.handle_new_user() returns trigger language plpgsql security definer set search_path = public as $$ begin insert into public.profiles (id,full_name,email,role,rank,is_active) values (new.id, coalesce(new.raw_user_meta_data ->> 'full_name', split_part(new.email, '@', 1)), new.email, 'member', 'omega', true) on conflict (id) do nothing; return new; end; $$;
create or replace function public.is_admin(uid uuid default auth.uid()) returns boolean language sql stable as $$ select exists (select 1 from public.profiles p where p.id = uid and p.role = 'admin' and p.is_active = true); $$;
create or replace function public.is_leader_or_admin(uid uuid default auth.uid()) returns boolean language sql stable as $$ select exists (select 1 from public.profiles p where p.id = uid and p.role in ('leader','admin') and p.is_active = true); $$;
create or replace function public.is_active_member(uid uuid default auth.uid()) returns boolean language sql stable as $$ select exists (select 1 from public.profiles p where p.id = uid and p.is_active = true); $$;
create table if not exists public.profiles (id uuid primary key references auth.users(id) on delete cascade, full_name text not null, email text unique not null, phone text, bio text, role public.app_role not null default 'member', rank public.pack_rank not null default 'omega', pack_role text, sponsor_name text, joined_at date default current_date, is_active boolean not null default true, avatar_url text, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table if not exists public.join_requests (id uuid primary key default gen_random_uuid(), full_name text not null, email text not null, phone text, message text, interested_in_visiting boolean not null default false, status public.join_request_status not null default 'submitted', reviewed_by uuid references public.profiles(id) on delete set null, reviewed_at timestamptz, created_at timestamptz not null default now());
create table if not exists public.accountability_entries (id uuid primary key default gen_random_uuid(), user_id uuid not null references public.profiles(id) on delete cascade, entry_month smallint not null check (entry_month between 1 and 12), entry_year integer not null check (entry_year >= 2024), spiritual_goal text, personal_goal text, professional_goal text, physical_goal text, emotional_goal text, weekly_notes text, wins text, obstacles text, meeting_attended boolean not null default false, book_completed boolean not null default false, scripture_memorized boolean not null default false, helped_member_note text, commitments_declared text, commitments_completed text, created_at timestamptz not null default now(), updated_at timestamptz not null default now(), constraint accountability_one_entry_per_month unique (user_id, entry_month, entry_year));
create table if not exists public.meetings (id uuid primary key default gen_random_uuid(), title text not null, meeting_date timestamptz not null, status public.meeting_status not null default 'draft', monthly_scripture text, monthly_priorities text, arrival_transition text, opening_anchor text, code_reaffirmation text, ownership_round text, council_reflection text, practical_alignment text, open_business text, commitment_declarations text, closing_anchor text, printable_pdf_url text, created_by uuid references public.profiles(id) on delete set null, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table if not exists public.meeting_notes (id uuid primary key default gen_random_uuid(), meeting_id uuid not null references public.meetings(id) on delete cascade, summary text, notes text, action_items text, uploaded_file_url text, created_by uuid references public.profiles(id) on delete set null, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table if not exists public.documents (id uuid primary key default gen_random_uuid(), title text not null, category public.document_category not null default 'other', description text, file_url text not null, is_public boolean not null default false, uploaded_by uuid references public.profiles(id) on delete set null, version_label text, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table if not exists public.scholarship_applications (id uuid primary key default gen_random_uuid(), student_name text not null, email text not null, phone text, school_name text, gpa numeric(3,2), intended_path text, activities text, essay_prompt text, essay_file_url text, recommendation_file_url text, transcript_file_url text, status public.scholarship_status not null default 'submitted', review_notes text, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table if not exists public.merch_products (id uuid primary key default gen_random_uuid(), name text not null, slug text unique not null, description text, image_url text, price_text text, is_active boolean not null default true, sort_order integer not null default 0, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table if not exists public.merch_orders (id uuid primary key default gen_random_uuid(), product_id uuid references public.merch_products(id) on delete set null, customer_name text not null, email text not null, phone text, size text, quantity integer not null default 1 check (quantity > 0), notes text, status public.merch_order_status not null default 'new', created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table if not exists public.discussion_threads (id uuid primary key default gen_random_uuid(), title text not null, category public.thread_category not null default 'open', created_by uuid not null references public.profiles(id) on delete cascade, is_pinned boolean not null default false, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table if not exists public.discussion_posts (id uuid primary key default gen_random_uuid(), thread_id uuid not null references public.discussion_threads(id) on delete cascade, user_id uuid not null references public.profiles(id) on delete cascade, body text not null, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create or replace function public.set_updated_at() returns trigger language plpgsql as $$ begin new.updated_at = now(); return new; end; $$;
drop trigger if exists set_profiles_updated_at on public.profiles; create trigger set_profiles_updated_at before update on public.profiles for each row execute function public.set_updated_at();
drop trigger if exists set_accountability_updated_at on public.accountability_entries; create trigger set_accountability_updated_at before update on public.accountability_entries for each row execute function public.set_updated_at();
drop trigger if exists set_meetings_updated_at on public.meetings; create trigger set_meetings_updated_at before update on public.meetings for each row execute function public.set_updated_at();
drop trigger if exists set_meeting_notes_updated_at on public.meeting_notes; create trigger set_meeting_notes_updated_at before update on public.meeting_notes for each row execute function public.set_updated_at();
drop trigger if exists set_documents_updated_at on public.documents; create trigger set_documents_updated_at before update on public.documents for each row execute function public.set_updated_at();
drop trigger if exists set_scholarship_updated_at on public.scholarship_applications; create trigger set_scholarship_updated_at before update on public.scholarship_applications for each row execute function public.set_updated_at();
drop trigger if exists set_merch_products_updated_at on public.merch_products; create trigger set_merch_products_updated_at before update on public.merch_products for each row execute function public.set_updated_at();
drop trigger if exists set_merch_orders_updated_at on public.merch_orders; create trigger set_merch_orders_updated_at before update on public.merch_orders for each row execute function public.set_updated_at();
drop trigger if exists set_discussion_threads_updated_at on public.discussion_threads; create trigger set_discussion_threads_updated_at before update on public.discussion_threads for each row execute function public.set_updated_at();
drop trigger if exists set_discussion_posts_updated_at on public.discussion_posts; create trigger set_discussion_posts_updated_at before update on public.discussion_posts for each row execute function public.set_updated_at();
drop trigger if exists on_auth_user_created on auth.users; create trigger on_auth_user_created after insert on auth.users for each row execute procedure public.handle_new_user();
create index if not exists idx_profiles_role on public.profiles(role); create index if not exists idx_profiles_rank on public.profiles(rank); create index if not exists idx_accountability_user_month_year on public.accountability_entries(user_id, entry_year desc, entry_month desc); create index if not exists idx_meetings_status_date on public.meetings(status, meeting_date desc); create index if not exists idx_documents_category_public on public.documents(category, is_public); create index if not exists idx_scholarship_status on public.scholarship_applications(status); create index if not exists idx_merch_products_active_sort on public.merch_products(is_active, sort_order); create index if not exists idx_merch_orders_status on public.merch_orders(status); create index if not exists idx_threads_category_created on public.discussion_threads(category, created_at desc); create index if not exists idx_posts_thread_created on public.discussion_posts(thread_id, created_at asc);
alter table public.profiles enable row level security; alter table public.join_requests enable row level security; alter table public.accountability_entries enable row level security; alter table public.meetings enable row level security; alter table public.meeting_notes enable row level security; alter table public.documents enable row level security; alter table public.scholarship_applications enable row level security; alter table public.merch_products enable row level security; alter table public.merch_orders enable row level security; alter table public.discussion_threads enable row level security; alter table public.discussion_posts enable row level security;
create policy "profiles readable by active members" on public.profiles for select using (public.is_active_member());
create policy "profiles self update" on public.profiles for update using (auth.uid() = id) with check (auth.uid() = id);
create policy "profiles admin update" on public.profiles for update using (public.is_admin()) with check (public.is_admin());
create policy "public can submit join requests" on public.join_requests for insert to anon, authenticated with check (true);
create policy "leaders can read join requests" on public.join_requests for select using (public.is_leader_or_admin());
create policy "leaders can update join requests" on public.join_requests for update using (public.is_leader_or_admin()) with check (public.is_leader_or_admin());
create policy "members read own accountability" on public.accountability_entries for select using (auth.uid() = user_id or public.is_leader_or_admin());
create policy "members insert own accountability" on public.accountability_entries for insert with check (auth.uid() = user_id);
create policy "members update own accountability" on public.accountability_entries for update using (auth.uid() = user_id or public.is_leader_or_admin()) with check (auth.uid() = user_id or public.is_leader_or_admin());
create policy "members delete own accountability or admin" on public.accountability_entries for delete using (auth.uid() = user_id or public.is_admin());
create policy "members read published meetings" on public.meetings for select using (public.is_active_member() and (status = 'published' or public.is_leader_or_admin()));
create policy "leaders manage meetings" on public.meetings for all using (public.is_leader_or_admin()) with check (public.is_leader_or_admin());
create policy "members read notes for visible meetings" on public.meeting_notes for select using (exists (select 1 from public.meetings m where m.id = meeting_id and (m.status = 'published' or public.is_leader_or_admin()) and public.is_active_member()));
create policy "leaders manage meeting notes" on public.meeting_notes for all using (public.is_leader_or_admin()) with check (public.is_leader_or_admin());
create policy "public reads public docs" on public.documents for select using (is_public = true or public.is_active_member());
create policy "leaders manage documents" on public.documents for all using (public.is_leader_or_admin()) with check (public.is_leader_or_admin());
create policy "public can submit scholarship applications" on public.scholarship_applications for insert to anon, authenticated with check (true);
create policy "leaders read scholarship applications" on public.scholarship_applications for select using (public.is_leader_or_admin());
create policy "leaders update scholarship applications" on public.scholarship_applications for update using (public.is_leader_or_admin()) with check (public.is_leader_or_admin());
create policy "public read active merch products" on public.merch_products for select using (is_active = true or public.is_leader_or_admin());
create policy "leaders manage merch products" on public.merch_products for all using (public.is_leader_or_admin()) with check (public.is_leader_or_admin());
create policy "public can submit merch orders" on public.merch_orders for insert to anon, authenticated with check (true);
create policy "leaders read merch orders" on public.merch_orders for select using (public.is_leader_or_admin());
create policy "leaders update merch orders" on public.merch_orders for update using (public.is_leader_or_admin()) with check (public.is_leader_or_admin());
create policy "members read threads" on public.discussion_threads for select using (public.is_active_member());
create policy "members create threads" on public.discussion_threads for insert with check (public.is_active_member() and auth.uid() = created_by);
create policy "owners or leaders update threads" on public.discussion_threads for update using (auth.uid() = created_by or public.is_leader_or_admin()) with check (auth.uid() = created_by or public.is_leader_or_admin());
create policy "owners or admins delete threads" on public.discussion_threads for delete using (auth.uid() = created_by or public.is_admin());
create policy "members read posts" on public.discussion_posts for select using (public.is_active_member());
create policy "members create posts" on public.discussion_posts for insert with check (public.is_active_member() and auth.uid() = user_id);
create policy "owners or leaders update posts" on public.discussion_posts for update using (auth.uid() = user_id or public.is_leader_or_admin()) with check (auth.uid() = user_id or public.is_leader_or_admin());
create policy "owners or admins delete posts" on public.discussion_posts for delete using (auth.uid() = user_id or public.is_admin());
insert into public.merch_products (name, slug, description, price_text, is_active, sort_order) values ('BOG Black Tee', 'bog-black-tee', 'Black tee with front chest logo and large Buffalo Dog / BOG back graphic.', 'Set by admin', true, 1), ('BOG Puff Hat', 'bog-puff-hat', 'Black hat with 3D puff embroidered logo.', 'Set by admin', true, 2) on conflict (slug) do nothing;
